import os
import torch
import numpy as np
from PIL import Image
from pathlib import Path
import copy
import json
from lerobot.policies.pi0 import PI0Policy
from lerobot.policies.factory import make_pre_post_processors
os.environ['HF_HUB_OFFLINE'] = '1'
print('Starting FULL preprocess diagnostic for PI0 (testing actual preprocess call)...')
policy = PI0Policy.from_pretrained('lerobot/pi0_base')
preprocess, postprocess = make_pre_post_processors(
    policy.config,
    'lerobot/pi0_base',
    preprocessor_overrides={'device_processor': {'device': 'cpu'}}
)
print('\nType of preprocess:', type(preprocess))
print('Available attrs:', [attr for attr in dir(preprocess) if not attr.startswith('_')])
steps = None
for attr_name in ['processors', 'pipeline', 'transforms', 'steps']:
    if hasattr(preprocess, attr_name):
        steps = getattr(preprocess, attr_name)
        print(f'Found steps via .{attr_name} (len={len(steps) if hasattr(steps, "__len__") else "?"})')
        break
if steps is None:
    print('No steps list found.')
    steps = []
else:
    print('\nPipeline steps:')
    for i, step in enumerate(steps):
        print(i, type(step).__name__)
print('\nNow testing FULL preprocess calls on variants with dummy action and padded state.')
instruction = 'Add bbq_sauce to the dish on the table.'
rgb = np.random.randint(0, 255, (4, 480, 480, 3), dtype=np.uint8)
def create_images(as_pil=True):
    view_indices = [0, 1, 2]
    view_names = ['base_0_rgb', 'left_wrist_0_rgb', 'right_wrist_0_rgb']
    images = {}
    for name, idx in zip(view_names, view_indices):
        img_array = rgb[idx]
        if as_pil:
            img_pil = Image.fromarray(img_array)
            img_pil = img_pil.resize((224, 224), Image.BILINEAR)
            images[name] = img_pil
        else:
            img_pil = Image.fromarray(img_array)
            img_pil = img_pil.resize((224, 224), Image.BILINEAR)
            images[name] = np.array(img_pil).transpose(2, 0, 1).astype(np.float32) / 255.0
    return images
state_np = np.random.rand(8).astype(np.float32)
state = torch.from_numpy(state_np).unsqueeze(0).float()
state_padded = torch.zeros((1, 32), dtype=torch.float32)
state_padded[:, :8] = state
dummy_action = torch.zeros((1, 32), dtype=torch.float32)
formats = [
    ('complementary_pil_padded', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded},
        'action': dummy_action,
        'complementary_data': {'task': instruction}
    }),
    ('complementary_pil_padded_taskroot', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded},
        'action': dummy_action,
        'complementary_data': {'task': instruction},
        'task': instruction
    }),
    ('complementary_tensor_padded', lambda: {
        'observation': {'images': create_images(False), 'state': state_padded},
        'action': dummy_action,
        'complementary_data': {'task': instruction}
    }),
    ('taskroot_only_pil', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded},
        'action': dummy_action,
        'task': instruction
    }),
    ('flat_images_state', lambda: {
        'images': create_images(True),
        'state': state_padded,
        'action': dummy_action,
        'task': instruction
    }),
    ('transition_like_full', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded},
        'action': dummy_action,
        'complementary_data': {'task': instruction},
        'task': instruction,
        'language': {'tokens': torch.zeros((1, 20), dtype=torch.long)}  # pre-add to test
    }),
    ('no_dummy_action', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded},
        'complementary_data': {'task': instruction}
    }),
    ('minimal_observation_only', lambda: {
        'observation': {'images': create_images(True), 'state': state_padded, 'language': {'task': instruction}},
        'action': dummy_action
    }),
]
working_format = None
for name, batch_func in formats:
    print(f'\n--- Testing FULL preprocess {name} ---')
    original = batch_func()
    print('Initial keys:', list(original.keys()))
    if 'observation' in original:
        print('  observation subkeys:', list(original['observation'].keys()))
    try:
        current = copy.deepcopy(original)
        processed = preprocess(current)
        print('  FULL PREPROCESS SUCCEEDED!')
        if isinstance(processed, dict):
            print('  Final keys:', list(processed.keys()))
            if 'observation' in processed and isinstance(processed['observation'], dict):
                obs_sub = list(processed['observation'].keys())
                print('  obs subkeys:', obs_sub)
                if any('language' in k or 'tokens' in str(k) for k in obs_sub):
                    print('  Language tokens detected - GOOD!')
        working_format = name
        break  # stop at first success
    except Exception as e:
        print(f'  FAILED: {type(e).__name__}: {str(e)}')
        import traceback
        traceback.print_exc()
if working_format:
    print(f'\nSUCCESS: Use format "{working_format}" in predict.py')
else:
    print('\nNo format fully succeeded - try manual language tokenization next.')
print('\nDiagnostic complete.')
